        let where_clause = if where_sql.is_empty() { String::new() } else { format!(" WHERE {}", where_sql.join(" AND ")) };
        let sql = format!("UPDATE countries SET {} = {} + {} {}", col.as_sql(), col.as_sql(), amount, where_clause);
